security_findings.evidence:
UNPATCHED GpiopInitializePrimaryDevice (a1 = buffer, a2 = component count, a9 = device context):
  *(_QWORD *)(a1 + 48) = 0;
  *(_QWORD *)(a1 + 24) = GpioClxBankIdleStateCallback;
  *(_QWORD *)(a1 + 8)  = GpioClxBankActiveConditionCallback;
  *(_QWORD *)(a1 + 16) = GpioClxBankIdleConditionCallback;
  *(_QWORD *)(a1 + 32) = GpioClxDevicePowerRequiredCallback;
  *(_QWORD *)(a1 + 40) = GpioClxDevicePowerNotRequiredCallback;
  *(_QWORD *)(a1 + 64) = a9;
  *(_QWORD *)(a1 + 56) = GpioClxCriticalTransitionCallback;
  *(_DWORD *)a1 = 1;
  *(_DWORD *)(a1 + 4) = a2;

PATCHED GpiopInitializePrimaryDevice:
  *(_QWORD *)(a1 + 56) = 0;
  *(_DWORD *)a1 = 1;
  *(_DWORD *)(a1 + 8) = 1;   // new DWORD field
  *(_QWORD *)(a1 + 32) = GpioClxBankIdleStateCallback;
  *(_QWORD *)(a1 + 16) = GpioClxBankActiveConditionCallback;
  *(_QWORD *)(a1 + 24) = GpioClxBankIdleConditionCallback;
  *(_QWORD *)(a1 + 40) = GpioClxDevicePowerRequiredCallback;
  *(_QWORD *)(a1 + 48) = GpioClxDevicePowerNotRequiredCallback;
  *(_QWORD *)(a1 + 72) = a9;
  *(_QWORD *)(a1 + 64) = GpioClxCriticalTransitionCallback;
  *(_DWORD *)(a1 + 4) = a2;

GpiopGetBaseRegistrationBufferSize: return 104 (0x68) unpatched -> return 112 (0x70) patched.
